const urlString = $.input.businessUrls || '';
const urls = urlString.split(',').map(function(u) { return u.trim(); }).filter(function(u) { return u.length > 0 && (u.startsWith('http://') || u.startsWith('https://')); });
return { urls: urls, urlCount: urls.length };

const urls = $.steps.parseUrls.output.urls;
const iterations = $.steps.scrapeBusinesses.response?.iterations || [];
let allContent = '';
let successCount = 0;

urls.forEach(function(url, i) {
  const iter = iterations[i] || {};
  const resp = iter.scrapeSite?.response?.data || iter.scrapeSite?.response || {};
  const md = resp.markdown || resp.content || '';
  if (md) {
    successCount++;
    allContent += '=== BUSINESS ' + (i + 1) + ' ===\n';
    allContent += 'URL: ' + url + '\n';
    allContent += 'Content:\n' + md.slice(0, 4000) + '\n\n';
  } else {
    allContent += '=== BUSINESS ' + (i + 1) + ' (FAILED) ===\nURL: ' + url + '\n\n';
  }
});

return { allContent: allContent, successCount: successCount, totalCount: urls.length, industry: $.input.industry || '' };

const data = $.steps.compileBusinessData.output;

let prompt = 'You are a business data extraction specialist. Extract contact information and business details from the following scraped websites.

';
if (data.industry) prompt += 'INDUSTRY CONTEXT: ' + data.industry + '
';
prompt += 'BUSINESSES SCRAPED: ' + data.successCount + '

';
prompt += data.allContent + '

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Extract all contact info: emails, phone numbers, physical addresses
';
prompt += '- Identify social media profiles (LinkedIn, Twitter, Facebook)
';
prompt += '- Extract business name, industry, services offered
';
prompt += '- Find key personnel names and roles if available

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "businesses": [
';
prompt += '    {
';
prompt += '      "name": "business name",
';
prompt += '      "url": "website",
';
prompt += '      "emails": [""],
';
prompt += '      "phones": [""],
';
prompt += '      "address": "",
';
prompt += '      "socialProfiles": { "linkedin": "", "twitter": "", "facebook": "" },
';
prompt += '      "services": [""],
';
prompt += '      "keyPeople": [{ "name": "", "role": "" }],
';
prompt += '      "industry": ""
';
prompt += '    }
';
prompt += '  ],
';
prompt += '  "totalContacts": 0,
';
prompt += '  "summary": "overview of extracted data"
';
prompt += '}';
return { prompt };

let raw = $.steps.aiExtraction.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { businesses: [], totalContacts: 0, summary: raw.slice(0, 300) }; }

const ai = $.steps.parseAI.output;
const rows = [];
const businesses = ai.businesses || [];
businesses.forEach(function(b) {
  rows.push([
    b.name || '',
    b.url || '',
    (b.emails || []).join(', '),
    (b.phones || []).join(', '),
    b.address || '',
    b.socialProfiles?.linkedin || '',
    b.socialProfiles?.twitter || '',
    (b.services || []).join(', '),
    (b.keyPeople || []).map(function(p) { return p.name + ' (' + p.role + ')'; }).join(', '),
    b.industry || ''
  ]);
});
return { rows: rows };

const ai = $.steps.parseAI.output;
const stats = $.steps.compileBusinessData.output;
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Business Scraping Results', emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Businesses Scraped:*\n' + stats.successCount + '/' + stats.totalCount },
  { type: 'mrkdwn', text: '*Contacts Found:*\n' + (ai.totalContacts || 0) }
] });
blocks.push({ type: 'divider' });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary:*\n' + (ai.summary || '').slice(0, 1500) } });

const businesses = ai.businesses || [];
businesses.slice(0, 5).forEach(function(b) {
  let text = '*' + (b.name || 'Unknown') + '* - <' + (b.url || '#') + '|Website>';
  if (b.emails && b.emails.length > 0) text += '\nEmails: ' + b.emails.join(', ');
  if (b.phones && b.phones.length > 0) text += '\nPhones: ' + b.phones.join(', ');
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text.slice(0, 1800) } });
});

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Saved to Google Sheets | Powered by Firecrawl + Claude AI' }] });
const fallbackText = 'Business Scraping: ' + stats.successCount + ' businesses, ' + (ai.totalContacts || 0) + ' contacts extracted';
return { blocks, fallbackText };
